package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.Constructor;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  static class TestRecord {
    public int x;
  }

  static class NonRecord {
  }

  @BeforeAll
  static void setup() {
    // No setup needed for static final RECORD_HELPER as it is initialized in ReflectionHelper
  }

  @Test
  void isRecord_returnsTrue_whenRecordHelperReturnsTrue() {
    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class, CALLS_REAL_METHODS)) {
      RecordHelper mockRecordHelper = mock(RecordHelper.class);
      mockedStatic.when(() -> ReflectionHelper.RECORD_HELPER).thenReturn(mockRecordHelper);
      when(mockRecordHelper.isRecord(TestRecord.class)).thenReturn(true);

      boolean result = ReflectionHelper.isRecord(TestRecord.class);

      assertTrue(result);
      verify(mockRecordHelper).isRecord(TestRecord.class);
    }
  }

  @Test
  void isRecord_returnsFalse_whenRecordHelperReturnsFalse() {
    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class, CALLS_REAL_METHODS)) {
      RecordHelper mockRecordHelper = mock(RecordHelper.class);
      mockedStatic.when(() -> ReflectionHelper.RECORD_HELPER).thenReturn(mockRecordHelper);
      when(mockRecordHelper.isRecord(NonRecord.class)).thenReturn(false);

      boolean result = ReflectionHelper.isRecord(NonRecord.class);

      assertFalse(result);
      verify(mockRecordHelper).isRecord(NonRecord.class);
    }
  }
}
